:root {
  --bg: #07111f;
  --bg-panel: rgba(9, 18, 32, 0.88);
  --bg-panel-strong: rgba(10, 22, 40, 0.96);
  --line: rgba(145, 178, 219, 0.24);
  --text: #ecf4ff;
  --muted: #a6bad6;
  --accent: #62b0ff;
  --accent-2: #ffd36d;
  --shadow: 0 18px 48px rgba(0, 0, 0, 0.35);
  --radius: 16px;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  min-height: 100%;
  background:
    radial-gradient(circle at top, #11213b 0%, #07111f 40%, #030813 100%);
  color: var(--text);
  font-family: Inter, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
}

body {
  min-height: 100vh;
}

button,
input,
select {
  font: inherit;
}

button:focus-visible,
input:focus-visible,
select:focus-visible {
  outline: 2px solid var(--accent-2);
  outline-offset: 2px;
}

.app-shell {
  min-height: 100vh;
  display: grid;
  grid-template-rows: auto 1fr;
  gap: 12px;
  padding: 12px;
}

.topbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  padding: 14px 16px;
  background: var(--bg-panel);
  border: 1px solid var(--line);
  border-radius: var(--radius);
  box-shadow: var(--shadow);
  backdrop-filter: blur(10px);
}

.topbar h1 {
  margin: 0;
  font-size: 1.35rem;
}

.subtitle {
  margin: 4px 0 0;
  color: var(--muted);
  font-size: 0.95rem;
}

.status-badge {
  padding: 8px 12px;
  border-radius: 999px;
  border: 1px solid rgba(98, 176, 255, 0.45);
  background: rgba(98, 176, 255, 0.12);
  color: #cfe6ff;
  white-space: nowrap;
}

.layout {
  display: grid;
  grid-template-columns: minmax(0, 1fr) 340px;
  gap: 12px;
  min-height: 0;
}

.viewer-panel,
.sidebar {
  min-height: 0;
}

.scene-container {
  position: relative;
  min-height: 68vh;
  height: 100%;
  border-radius: var(--radius);
  overflow: hidden;
  border: 1px solid var(--line);
  background: #020814;
  box-shadow: var(--shadow);
}

#scene-canvas {
  display: block;
  width: 100%;
  height: 100%;
}

.scene-overlay {
  position: absolute;
  left: 12px;
  bottom: 12px;
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  pointer-events: none;
}

.overlay-chip {
  padding: 6px 10px;
  border-radius: 999px;
  background: rgba(3, 10, 23, 0.72);
  border: 1px solid rgba(255, 255, 255, 0.12);
  color: var(--muted);
  font-size: 0.85rem;
}

.sidebar {
  display: grid;
  gap: 12px;
  align-content: start;
}

.panel {
  background: var(--bg-panel-strong);
  border: 1px solid var(--line);
  border-radius: var(--radius);
  padding: 14px;
  box-shadow: var(--shadow);
  backdrop-filter: blur(10px);
}

.panel h2 {
  margin-top: 0;
  margin-bottom: 12px;
  font-size: 1rem;
}

.control-grid {
  display: grid;
  gap: 10px;
}

.control-block {
  display: grid;
  gap: 6px;
  color: var(--muted);
}

.button-group {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-top: 12px;
}

button,
input[type="date"],
input[type="range"] {
  width: 100%;
}

button {
  padding: 10px 12px;
  border-radius: 10px;
  border: 1px solid rgba(255, 255, 255, 0.12);
  background: rgba(255, 255, 255, 0.06);
  color: var(--text);
}

button[disabled],
input[disabled] {
  opacity: 0.65;
  cursor: not-allowed;
}

.toggle-list {
  margin-top: 12px;
  display: grid;
  gap: 8px;
  color: var(--muted);
}

.info-panel dl {
  margin: 0;
  display: grid;
  gap: 10px;
}

.info-panel dl > div {
  display: grid;
  gap: 2px;
}

dt {
  color: var(--muted);
  font-size: 0.84rem;
}

dd {
  margin: 0;
}

.notes-panel p {
  margin: 0 0 10px;
  color: var(--muted);
  line-height: 1.5;
}

.notes-panel p:last-child {
  margin-bottom: 0;
}

@media (max-width: 980px) {
  .layout {
    grid-template-columns: 1fr;
  }

  .scene-container {
    min-height: 56vh;
  }
}

@media (max-width: 600px) {
  .app-shell {
    padding: 8px;
  }

  .topbar {
    flex-direction: column;
    align-items: flex-start;
  }

  .status-badge {
    white-space: normal;
  }

  .scene-container {
    min-height: 48vh;
  }
}

import * as THREE from 'https://cdn.jsdelivr.net/npm/three@0.160.0/build/three.module.js';

const canvas = document.getElementById('scene-canvas');
const container = document.getElementById('scene-container');

const renderer = new THREE.WebGLRenderer({
  canvas,
  antialias: true,
  alpha: false
});
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.setSize(container.clientWidth, container.clientHeight, false);
renderer.outputColorSpace = THREE.SRGBColorSpace;

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x020814);
scene.fog = new THREE.FogExp2(0x020814, 0.0009);

const camera = new THREE.PerspectiveCamera(
  50,
  container.clientWidth / container.clientHeight,
  0.1,
  2500
);
camera.position.set(0, 55, 155);

const ambientLight = new THREE.AmbientLight(0x8fa8c9, 0.7);
scene.add(ambientLight);

const keyLight = new THREE.PointLight(0xffddaa, 2.4, 0, 2);
keyLight.position.set(0, 0, 0);
scene.add(keyLight);

const rimLight = new THREE.DirectionalLight(0x7aa2ff, 0.6);
rimLight.position.set(-120, 90, 60);
scene.add(rimLight);

const sunGeometry = new THREE.SphereGeometry(10, 48, 48);
const sunMaterial = new THREE.MeshBasicMaterial({ color: 0xffc45a });
const sunMesh = new THREE.Mesh(sunGeometry, sunMaterial);
scene.add(sunMesh);

const glowGeometry = new THREE.SphereGeometry(13.5, 32, 32);
const glowMaterial = new THREE.MeshBasicMaterial({
  color: 0xffb347,
  transparent: true,
  opacity: 0.16
});
const sunGlow = new THREE.Mesh(glowGeometry, glowMaterial);
scene.add(sunGlow);

const gridGroup = new THREE.Group();
scene.add(gridGroup);

for (let i = 0; i < 5; i += 1) {
  const radius = 25 + i * 20;
  const orbit = new THREE.Mesh(
    new THREE.RingGeometry(radius - 0.12, radius + 0.12, 128),
    new THREE.MeshBasicMaterial({
      color: 0x35506f,
      transparent: true,
      opacity: 0.3,
      side: THREE.DoubleSide
    })
  );
  orbit.rotation.x = -Math.PI / 2;
  gridGroup.add(orbit);
}

function createStarField(count = 1800, spread = 1800) {
  const geometry = new THREE.BufferGeometry();
  const positions = new Float32Array(count * 3);
  const colors = new Float32Array(count * 3);
  const color = new THREE.Color();

  for (let i = 0; i < count; i += 1) {
    const i3 = i * 3;
    const radius = THREE.MathUtils.randFloat(spread * 0.35, spread);
    const theta = THREE.MathUtils.randFloat(0, Math.PI * 2);
    const phi = Math.acos(THREE.MathUtils.randFloatSpread(2));

    positions[i3] = radius * Math.sin(phi) * Math.cos(theta);
    positions[i3 + 1] = radius * Math.cos(phi);
    positions[i3 + 2] = radius * Math.sin(phi) * Math.sin(theta);

    color.setHSL(
      THREE.MathUtils.randFloat(0.52, 0.62),
      THREE.MathUtils.randFloat(0.2, 0.6),
      THREE.MathUtils.randFloat(0.7, 1.0)
    );
    colors[i3] = color.r;
    colors[i3 + 1] = color.g;
    colors[i3 + 2] = color.b;
  }

  geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
  geometry.setAttribute('color', new THREE.BufferAttribute(colors, 3));

  const material = new THREE.PointsMaterial({
    size: 3,
    sizeAttenuation: true,
    vertexColors: true,
    transparent: true,
    opacity: 0.95,
    depthWrite: false
  });

  return new THREE.Points(geometry, material);
}

const stars = createStarField();
scene.add(stars);

const accentStars = createStarField(220, 1200);
accentStars.material.size = 4.5;
accentStars.material.opacity = 0.5;
scene.add(accentStars);

const clock = new THREE.Clock();

function animate() {
  const elapsed = clock.getElapsedTime();
  sunMesh.rotation.y = elapsed * 0.15;
  sunGlow.rotation.y = -elapsed * 0.08;
  stars.rotation.y = elapsed * 0.01;
  accentStars.rotation.y = -elapsed * 0.015;
  gridGroup.rotation.z = elapsed * 0.02;

  renderer.render(scene, camera);
  requestAnimationFrame(animate);
}

function handleResize() {
  const width = container.clientWidth;
  const height = container.clientHeight;
  camera.aspect = width / height;
  camera.updateProjectionMatrix();
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.setSize(width, height, false);
}

window.addEventListener('resize', handleResize);
handleResize();
animate();
